import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';

import { HttpRequestsService } from '../../services/http-requests.service';

import { Gener } from '../../interfaces/gener';
import { Movie } from '../../interfaces/movie';


@Component
({
  selector: 'app-media-content',
  templateUrl: './media-content.component.html',
  styleUrls: ['./media-content.component.scss']
})
export class MediaContentComponent implements OnInit 
{
  public movieGener: Gener[]= [];
  public moviesList: { movies: Movie[] }[] = [];

  constructor(private httpRequestsService: HttpRequestsService, private router: Router) { }

  ngOnInit(): void 
  {
    this.httpRequestsService.getMoviegenerList()
    .subscribe
    (
      result=>
      {
        this.movieGener= result.genres;
        this.getMoviesListByGener();
      },
      error=>
      {
        console.log(error);
      }
    );
  }

  getMoviesListByGener()
  {
    this.movieGener.forEach
    (
      gener=>
      {
        this.httpRequestsService.getMoviesByGener(gener.id)
        .subscribe
        (
          result=>
          {
            let movieList= 
            {
              movies: []
            };

            movieList.movies= result.results;

            this.moviesList.push(movieList);
          },
          error=>
          {
            console.log(error);
          }
          
        );
      }
    );
  }

  openMedia(movie: Movie)
  {
    this.router.navigate(['detail', movie.id]);
  }

}
